--
-- Table structure for table `compras`
--

DROP TABLE IF EXISTS `compras`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `compras` (
  `id_compra` int(11) NOT NULL AUTO_INCREMENT,
  `sucursal` varchar(50) DEFAULT NULL,
  `bodega` varchar(100) DEFAULT NULL,
  `prov_datos` varchar(100) DEFAULT NULL,
  `dato_fac` varchar(50) NOT NULL,
  `fecha_emision` date DEFAULT NULL,
  `cred_cont` varchar(20) DEFAULT NULL,
  `dias_credito` int(11) DEFAULT NULL,
  `porcentaje_prima` decimal(5,2) DEFAULT NULL,
  `cuotas_pendientes` int(11) DEFAULT NULL,
  `otros_terminos` text DEFAULT NULL,
  `total` decimal(10,2) NOT NULL,
  `sub_total` decimal(10,2) NOT NULL,
  `fecha_registro` datetime NOT NULL,
  `isv_global` decimal(10,2) NOT NULL DEFAULT 0.00,
  `fech_vence` date NOT NULL,
  `numero_partida_contable` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`id_compra`),
  KEY `idx_compras_numero_partida_contable` (`numero_partida_contable`)
) ENGINE=InnoDB AUTO_INCREMENT=470 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
