DROP TABLE IF EXISTS `diario_general_transacciones`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `diario_general_transacciones` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `numero_partida` varchar(20) NOT NULL,
  `fecha_ocurrencia` date NOT NULL,
  `fecha_registro` datetime NOT NULL,
  `unidad_servicio` varchar(100) DEFAULT NULL,
  `cuenta` varchar(50) NOT NULL,
  `nombre_cuenta` varchar(255) NOT NULL,
  `descripcion` text NOT NULL,
  `debe` decimal(10,2) DEFAULT 0.00,
  `haber` decimal(10,2) DEFAULT 0.00,
  `neto` decimal(10,2) DEFAULT 0.00,
  `turno` varchar(50) DEFAULT NULL,
  `usuario` varchar(100) DEFAULT NULL,
  `tipo_transaccion` varchar(50) DEFAULT NULL,
  `referencia` varchar(100) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_numero_partida` (`numero_partida`),
  KEY `idx_fecha_ocurrencia` (`fecha_ocurrencia`),
  KEY `idx_cuenta` (`cuenta`),
  KEY `idx_fecha_registro` (`fecha_registro`)
) ENGINE=InnoDB AUTO_INCREMENT=325 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
