--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `orders` (
  `idord` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `processed_by` varchar(50) DEFAULT NULL,
  `nomcl` varchar(70) NOT NULL,
  `method` varchar(50) NOT NULL,
  `total_price` decimal(10,2) NOT NULL,
  `price_without_discount` decimal(10,2) NOT NULL,
  `discount_amount` decimal(10,2) NOT NULL DEFAULT 0.00,
  `tax_amount` decimal(10,2) NOT NULL DEFAULT 0.00 COMMENT 'Impuesto ISV calculado al momento del checkout (suma de items gravados 15%)',
  `placed_on` datetime DEFAULT NULL,
  `payment_status` varchar(20) NOT NULL,
  `tipc` varchar(25) NOT NULL,
  `invoice_number` varchar(20) DEFAULT NULL,
  `edad` int(11) DEFAULT NULL,
  `edad_calculada` int(11) DEFAULT NULL,
  `tipo` varchar(50) NOT NULL,
  `remitente` varchar(100) DEFAULT NULL,
  `dni_paciente` varchar(50) NOT NULL,
  `dni_manual` varchar(20) DEFAULT NULL,
  `pagador` varchar(100) DEFAULT NULL,
  `rtn_pagador` varchar(50) DEFAULT NULL,
  `num_poliza` varchar(50) DEFAULT NULL,
  `num_cuenta` varchar(50) DEFAULT NULL,
  `invoice_status` varchar(20) NOT NULL DEFAULT 'Pendiente',
  `updated_by` varchar(50) DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL COMMENT 'Fecha y hora del ??ltimo cambio de estado',
  `remite` varchar(255) DEFAULT NULL,
  `telefono_remite` varchar(20) DEFAULT NULL,
  `tipo_tarjeta` varchar(50) DEFAULT NULL COMMENT 'Tipo de tarjeta: Visa, Mastercard, etc.',
  `banco_emisor` varchar(100) DEFAULT NULL COMMENT 'Banco emisor de la tarjeta',
  `pos_cobrado` varchar(100) DEFAULT NULL COMMENT 'Terminal POS donde se proces?? el pago',
  `banco_transferencia` varchar(100) DEFAULT NULL COMMENT 'Banco para transferencias bancarias',
  `num_referencia` varchar(100) DEFAULT NULL COMMENT 'N??mero de referencia de la transferencia',
  `tipo_pago_mixto` varchar(100) DEFAULT NULL COMMENT 'Tipo de pago mixto: Tarjeta/Efectivo, Efectivo/Tarjeta',
  `banco_boton_pago` varchar(100) DEFAULT NULL,
  `num_referencia_boton_pago` varchar(100) DEFAULT NULL,
  `banco_transferencia_local` varchar(100) DEFAULT NULL,
  `num_referencia_transferencia_local` varchar(100) DEFAULT NULL,
  `banco_transferencia_internacional` varchar(100) DEFAULT NULL,
  `num_referencia_transferencia_internacional` varchar(100) DEFAULT NULL,
  `monto_recibido` decimal(10,2) DEFAULT NULL COMMENT 'Monto recibido del cliente en efectivo',
  `cambio_devolver` decimal(10,2) DEFAULT NULL COMMENT 'Cambio a devolver al cliente',
  `monto_tarjeta_mixto` decimal(10,2) DEFAULT NULL COMMENT 'Monto pagado con tarjeta en pago mixto',
  `monto_efectivo_mixto` decimal(10,2) DEFAULT NULL COMMENT 'Monto pagado en efectivo en pago mixto',
  `observacion_anulacion` text DEFAULT NULL COMMENT 'Motivo u observaci├│n de la anulaci├│n de la factura',
  `anulada_por` varchar(100) DEFAULT NULL,
  `anulada_at` datetime DEFAULT NULL,
  `telefono_paciente` varchar(30) DEFAULT NULL COMMENT 'Tel├®fono del paciente (ambulatorio manual)',
  PRIMARY KEY (`idord`),
  UNIQUE KEY `invoice_number` (`invoice_number`)
) ENGINE=InnoDB AUTO_INCREMENT=323 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

