DROP TABLE IF EXISTS `patients`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `patients` (
  `idpa` int(11) NOT NULL AUTO_INCREMENT,
  `numhs` char(13) NOT NULL,
  `nompa` varchar(30) NOT NULL,
  `apepa` varchar(30) NOT NULL,
  `direc` varchar(150) NOT NULL,
  `sex` varchar(15) NOT NULL,
  `grup` varchar(15) NOT NULL,
  `phon` char(13) NOT NULL,
  `cump` date NOT NULL,
  `resnamp` varchar(100) NOT NULL,
  `resgep` varchar(15) NOT NULL,
  `corr` varchar(35) NOT NULL,
  `username` varchar(25) NOT NULL,
  `password` varchar(255) NOT NULL,
  `rol` char(1) NOT NULL,
  `state` char(1) NOT NULL,
  `fere` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `dip_correo` varchar(255) NOT NULL,
  `profesion` varchar(255) NOT NULL,
  `estado_civic` varchar(50) NOT NULL,
  PRIMARY KEY (`idpa`)
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
