--
-- Table structure for table `proveedor_comercial`
--

DROP TABLE IF EXISTS `proveedor_comercial`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `proveedor_comercial` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `nombre_empresa` varchar(255) NOT NULL,
  `direccion` varchar(255) NOT NULL,
  `rtn_comercial` varchar(20) NOT NULL,
  `tel_fijo` varchar(15) DEFAULT NULL,
  `correo_comercial` varchar(255) NOT NULL,
  `cel_whatsapp` varchar(15) DEFAULT NULL,
  `nombre_legal` varchar(255) NOT NULL,
  `dni_comercial` varchar(20) NOT NULL,
  `cel_comercial` varchar(15) DEFAULT NULL,
  `cuenta_bac_comercial` varchar(50) DEFAULT NULL,
  `tipo_cuenta_comercial` varchar(50) DEFAULT NULL,
  `archivo_constancia_comercial` blob DEFAULT NULL,
  `nom_contacto` varchar(255) DEFAULT NULL,
  `fecha_registro` datetime DEFAULT current_timestamp(),
  `1_refbac_comercial` varchar(255) DEFAULT NULL,
  `1_refbac_comercial_tel` varchar(15) DEFAULT NULL,
  `2_refbac_comercial` varchar(255) DEFAULT NULL,
  `2_refbac_comercial_tel` varchar(15) DEFAULT NULL,
  `1_refbac_contacto` varchar(255) DEFAULT NULL,
  `1_refbac_contacto_tel` varchar(15) DEFAULT NULL,
  `firma_digital_comercial` blob DEFAULT NULL,
  `cuenta_bac_si` varchar(50) DEFAULT NULL,
  `cuenta_bac_no` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=100 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

