INSERT INTO `report_transcriptions` VALUES (7,16,1,'Ing. Mois??s Castillo',NULL,'completed','2025-06-06 19:57:05','2025-08-18 11:17:02','El medico receto ejemplo descriptivo para colocar m??s contenido del transcriptor','TOMOGRAF??A ABDOMINAL CONTRASTADA','2025-08-18 11:17:02','VES??CULA BILIAR DISTENDIDA CON LEVES CAMBIOS INFLAMATORIOS DE LA GRASA \n\nADYACENTE DE FORMA ASOCIADA Y DOS (2) LITOS EN SU INTERIOR, MIDEN 20 MM Y 19 MM, CONSIDERAR COLECISTITIS AGUDA LITI??SICA.\n-	ALTERACI??N DE LA DENSIDAD DE LA GRASA PERIRRENAL DE FORMA BILATERAL, CORRELACIONAR CON PRUEBAS DE FUNCI??N RENAL/EGO. \n-	ENFERMEDAD ATEROESCLER??TICA LEVE Y CAMBIOS OSTEODEGENERATIVOS. TAMBIEN SE IDENTIFICAN PLACAS ATEROMATOSAS CALCIFICADAS A NIVEL DE ARTERIAS CORONARIAS.\n-	ADENOMA DE GL??NDULAS SUPRARRENAL DERECHA. \n','Descripci??n - se eval??a tomograf??a abdominales fase simple y con medio de contraste endovenoso, donde observamos:\nEstructuras gastrointestinales: porci??n esof??gica inferior y uni??n gastroesof??gica de morfolog??a normal. C??mara g??strica no distendida, de situaci??n normal, sin alteraciones parietales evidentes. Intestino delgado y marco col??nico sin hallazgos patol??gicos. Ap??ndice cecal de morfolog??a normal, no presenta cambios inflamatorios. \nNo hay l??quido libre en cavidad abdominal ni presencia de linfadenopat??as. \nEstructuras vasculares en fase simple se identifican placas ateromatosas calcificadas parietales perif??ricas, en leve cantidad a nivel de la aorta abdominal y ramas iliacas comunes. Tras la administraci??n de medio de contraste hay adecuada opacificaci??n de estructuras arteriales y venosas. No se identifican defectos de llenado que sugieran trombosis. \nH??gado de forma, tama??o, situaci??n y densidad normal, l??bulo hep??tico derecho mide 155 mm. No se identifican lesiones focales o difusas en su par??nquima. \n','Se detecto ejemplo descriptivo para colocar m??s contenido del transcriptor'),(8,25,1,'Ing. Mois??s Castillo',NULL,'completed','2025-07-15 07:59:24','2025-07-15 07:59:24','ok','TRANSCRIPCI??N','2025-07-15 07:59:24','ok','ok','ok'),(9,26,1,'Ing. Mois??s Castillo',NULL,'completed','2025-08-18 17:30:30','2025-08-26 04:50:27','SE OBSERVA QUE SE REQUIERE UN INTERVERCION QUIRURGICA','INFORME RAYOS X DIGITAL','2025-08-26 05:06:18','DOLOR EN EL PECHO','CORAZ??N DE TAMA??O, FORMA Y POSICI??N NORMAL LA AORTA SE OBSERVA DENSA Y ELONGADA.\nLA TR??QUEA CENTRAL BIEN NEUMATIZADA.\nA NIVEL DEL PAR??NQUIMA PULMONAR SE OBSERVA QUE NO EXISTE LA PRESENCIA DE MASAS COLECCIONES NI\nCONSOLIDACIONES.\nLAS ESTRUCTURAS ??SEAS SE OBSERVAN OSTEOFITOS DORSALES.\nLOS TEJIDOS BLANDOS SON NORMALES ','CONCLUSI??N:\n1. AORTOESCLEROSIS.\n2. CAMBIOS OSTEODEGENERATIVOS. ');
