--
-- Table structure for table `worklist`
--

DROP TABLE IF EXISTS `worklist`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `worklist` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `study_id` varchar(100) DEFAULT NULL,
  `series_id` varchar(255) DEFAULT NULL,
  `patient_id` varchar(50) DEFAULT NULL,
  `patient_name` varchar(100) DEFAULT NULL,
  `study_date` datetime DEFAULT NULL,
  `modality` varchar(10) DEFAULT NULL,
  `study_description` text DEFAULT NULL,
  `technician_id` int(11) DEFAULT NULL,
  `technician_name` varchar(100) DEFAULT NULL,
  `status` enum('pending','in_progress','completed','cancelled') DEFAULT NULL,
  `priority` enum('routine','urgent','emergency') DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `last_sync` datetime DEFAULT NULL,
  `last_update` datetime DEFAULT NULL,
  `radiologist_id` int(11) DEFAULT NULL,
  `radiologist_name` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_study` (`study_id`),
  KEY `idx_last_update` (`last_update`),
  KEY `idx_study_id` (`study_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6085 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

